qry:select.qry:xquery:
				for $r in sql('
		SELECT 
		PER02_PERSONAL_EMP.oi_personal_emp, PER02_PERSONAL_EMP.e_numero_legajo, PER01_PERSONAL.d_ape_y_nom

		FROM 
		PER01_PERSONAL, PER02_PERSONAL_EMP, LIQ07_ANTICIPOS, LIQ07_DESC_ANTI

		JOIN
		PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal,
		PER02_PERSONAL_EMP.oi_personal_emp INNER LIQ07_ANTICIPOS.oi_personal_emp,
		LIQ07_ANTICIPOS.oi_anticipo LEFT OUTER LIQ07_DESC_ANTI.oi_anticipo

		WHERE
		PER02_PERSONAL_EMP.oi_empresa = {#PARAMIN:@oi_empresa}
		{%?(#PARAMIN:@f_desde_anticipo!='') {% AND LIQ07_ANTICIPOS.f_anticipo >= {DateTime(#PARAMIN:@f_desde_anticipo)} %} {% %} %}
		{%?(#PARAMIN:@f_hasta_anticipo!='') {% AND LIQ07_ANTICIPOS.f_anticipo <= {DateTime(#PARAMIN:@f_hasta_anticipo)} %} {% %} %}
		{%?(#PARAMIN:@c_estado!='') {% AND LIQ07_ANTICIPOS.c_estado = {#PARAMIN:@c_estado} %} {% %} %}
  		{%?(#PARAMIN:@oi_tipo_anticipo!='') {% AND LIQ07_ANTICIPOS.oi_tipo_anticipo = {#PARAMIN:@oi_tipo_anticipo} %} {% %} %}
		{%?(string(#PARAMIN:PERSONAS/PERSONA/@id)!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#PARAMIN:PERSONAS/PERSONA/@id) %}) %} {%  %} %}

		GROUP BY PER02_PERSONAL_EMP.oi_personal_emp, PER02_PERSONAL_EMP.e_numero_legajo, PER01_PERSONAL.d_ape_y_nom

	')/ROWS/ROW
